UPDATE t_p7851806_project_inovation_la.site_content
SET value = '{"title": "Ваша первая и главная задача: Получить допуск к лечению.", "content": "<p>До получения допуска к лечению Вам нельзя абсолютно ничего. Лечить пациентов сможете только тогда, когда получите допуск к лечению.</p><p><strong>Чтобы получить допуск, Вам нужно сдать:</strong></p><ol><li>Прослушать вступительную лекцию;</li><li><strong>Сдать устную речь</strong> — это бинды. Слово \\"Бинд\\" в РП мы не используем!</li><li><strong>Сдать Первичный Медицинский Экзамен (ПМЭ)</strong>, который включает: информацию о больнице, практический экзамен по выдаче препаратов, вопросы по Внутреннему уставу.</li><li>Сдать клятву врача.</li></ol>", "binds_link": "https://forum.gtaprovince.ru/topic/995732-cgb-g-nevskiy-bindy-dlya-sotrudnikov/", "charter_link": "https://forum.gtaprovince.ru/topic/995741-cgb-g-nevskiy-vnutrenniy-ustav/"}'
WHERE key = 'intern_exam';